class ElasticsearchLogHandler(logging.Handler):
    def __init__(
        self,
        platform: ElasticsearchPlatform,
        level: int = logging.INFO,
        service: str = "platform",
        environment: str = "production",
    ) -> None:
        super().__init__(level=level)
        self.platform = platform
        self.service = service
        self.environment = environment

    def emit(self, record: logging.LogRecord) -> None:
        try:
            fields = {
                "pathname": record.pathname,
                "filename": record.filename,
                "module": record.module,
                "funcName": record.funcName,
                "lineno": record.lineno,
                "process": record.process,
                "thread": record.thread,
            }

            if hasattr(record, "extra_fields") and isinstance(record.extra_fields, dict):
                fields.update(record.extra_fields)

            self.platform.index_log(
                message=self.format(record),
                level=record.levelname,
                logger_name=record.name,
                service=self.service,
                environment=self.environment,
                trace_id=getattr(record, "trace_id", None),
                fields=fields,
                refresh=False,
            )
        except Exception:
            self.handleError(record)


def print_json(data: Any) -> None:
    print(json.dumps(data, indent=2, default=str))


def demo(platform: ElasticsearchPlatform) -> None:
    platform.ensure_indices()

    docs = [
        {
            "id": "doc-1",
            "title": "Centralized Logging with Elasticsearch",
            "content": "Elasticsearch enables scalable full-text search and centralized logging.",
            "tags": ["logging", "elasticsearch", "search"],
            "author": "ops-team",
            "metadata": {"category": "observability"},
        },
        {
            "id": "doc-2",
            "title": "Search Platform Overview",
            "content": "Our platform supports indexing, search queries, and aggregation pipelines.",
            "tags": ["search", "platform"],
            "author": "engineering",
            "metadata": {"category": "architecture"},
        },
    ]
    print_json(platform.bulk_index_documents(docs))

    log_records = [
        {
            "level": "INFO",
            "logger": "api",
            "message": "Request completed successfully",
            "service": "gateway",
            "environment": "production",
            "fields": {"status_code": 200, "path": "/health"},
        },
        {
            "level": "ERROR",
            "logger": "worker",
            "message": "Failed to process job",
            "service": "jobs",
            "environment": "production",
            "fields": {"job_id": "job-123", "reason": "timeout"},
        },
        {
            "level": "WARN",
            "logger": "api",
            "message": "Slow request detected",
            "service": "gateway",
            "environment": "production",
            "fields": {"duration_ms": 1450, "path": "/search"},
        },
    ]
    print_json(platform.bulk_index_logs(log_records))

    time.sleep(1)

    print_json(platform.search_documents("centralized logging"))
    print_json(platform.search_logs(query="failed OR slow", environment="production"))
    print_json(platform.aggregate_logs(interval="1h", environment="production"))
    print_json(platform.count_logs(environment="production"))


def configure_python_logger(platform: ElasticsearchPlatform) -> logging.Logger:
    logger = logging.getLogger("centralized-platform")
    logger.setLevel(logging.INFO)

    if not any(isinstance(h, ElasticsearchLogHandler) for h in logger.handlers):
        handler = ElasticsearchLogHandler(
            platform=platform,
            service="python-app",
            environment="production",
        )
        formatter = logging.Formatter("%(asctime)s %(name)s %(levelname)s %(message)s")
        handler.setFormatter(formatter)
        logger.addHandler(handler)

    if not any(isinstance(h, logging.StreamHandler) for h in logger.handlers):
        stream_handler = logging.StreamHandler(sys.stdout)
        stream_handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
        logger.addHandler(stream_handler)

    return logger


def main() -> None:
    platform = ElasticsearchPlatform(hosts=["http://localhost:9200"])

    if not platform.ping():
        raise RuntimeError("Could not connect to Elasticsearch at localhost:9200")

    platform.ensure_indices()

    logger = configure_python_logger(platform)
    logger.info("Application started", extra={"extra_fields": {"component": "bootstrap"}})
    logger.error(
        "Sample error for aggregation",
        extra={"extra_fields": {"component": "demo", "error_code": "E1001"}},
    )

    demo(platform)


if __name__ == "__main__":
    main()